import com.atlassian.jira.component.ComponentAccessor
import com.atlassian.jira.issue.MutableIssue

def issueManager = ComponentAccessor.getIssueManager()
def userManager = ComponentAccessor.getUserManager()
def customFieldManager = ComponentAccessor.getCustomFieldManager()

def issue = issueManager.getIssueObject('BUG-42')
def customField = customFieldManager.getCustomFieldObjectByName('Team Lead')
def teamLead = customField ? issue.getCustomFieldValue(customField) : null

if (teamLead) {
    def user = userManager.getUserByName(teamLead.toString())
    if (user) {
        issue.setAssignee(user)
        issueManager.updateIssue(ComponentAccessor.jiraAuthenticationContext.loggedInUser, issue, com.atlassian.jira.event.type.EventDispatchOption.DO_NOT_DISPATCH, false)
    }
}

